defmodule MyAppWeb.UserController do
  use MyAppWeb, :controller
  alias MyApp.{Repo, User}

  def update(conn, %{"id" => user_id}) do
    user = Repo.get_by_id(User, user_id)

    if is_nil(user) do
      conn
      |> put_status(:not_found)
      |> render("errors/404")
      |> halt
    end

    changeset = User.changeset(user, params)

    case Changeset.validate_required(changeset) do
      {:ok, changeset} ->
        updated_user = Repo.update(user, Ecto.Changeset.changeset_data(changeset))
        {:ok, conn, updated_user}

      {err, _} ->
        case Repo.invalid_param_changeset(changeset) do
          {valid_params, invalid_params} ->
            conn
            |> put_flash(:error, "Invalid parameters: #{inspect(invalid_params)}")
            |> redirect(to: Routes.user_path(conn, :edit, id: user_id))
        end
    end
  end
end